/**
 * End-to-end smoke test for the knotgraft fabric server.
 *
 * Binds real ports for HTTP + TCP Flow + UDP Flow, sends the same
 * payload over each transport, and verifies all three return
 * soundness-identical settled-block shapes (tenant, totalBytes,
 * laneCount all match).
 */

import { describe, expect, it } from '@a0n/gnosis/test';
import { Socket, createConnection } from 'node:net';
import { createSocket } from 'node:dgram';
import { FlowCodec } from '@a0n/aeon/flow';
import { startKnotgraftFabric } from '../knotgraft-fabric-server';

const HTTP_PORT = 7801;
const TCP_PORT = 4244;
const UDP_PORT = 4245;

function makeBytes(n: number): Uint8Array {
  const out = new Uint8Array(n);
  for (let i = 0; i < n; i++) out[i] = (i * 53) & 0xff;
  return out;
}

function frame4(bytes: Uint8Array): Buffer {
  const buf = Buffer.alloc(4 + bytes.length);
  buf.writeUInt32BE(bytes.length, 0);
  buf.set(bytes, 4);
  return buf;
}

async function httpIngest(bytes: Uint8Array): Promise<Record<string, unknown>> {
  const res = await fetch(`http://127.0.0.1:${HTTP_PORT}/ingest`, {
    method: 'POST',
    headers: { 'content-type': 'application/octet-stream' },
    body: bytes,
  });
  if (!res.ok) throw new Error(`HTTP ${res.status}`);
  return (await res.json()) as Record<string, unknown>;
}

function tcpIngest(bytes: Uint8Array, codec: FlowCodec): Promise<Record<string, unknown>> {
  return new Promise((resolve, reject) => {
    const socket: Socket = createConnection(TCP_PORT, '127.0.0.1');
    const timeout = setTimeout(() => {
      socket.destroy();
      reject(new Error('TCP timeout'));
    }, 10_000);
    let rx: Buffer = Buffer.alloc(0);

    socket.once('connect', () => {
      const req = codec.encode({
        streamId: 77,
        sequence: 0,
        flags: 0,
        payload: bytes,
      });
      // aeon fabric uses self-describing framing (no outer length prefix).
      socket.write(req);
    });

    socket.on('data', (chunk: Buffer) => {
      rx = Buffer.concat([rx, chunk]);
      while (rx.length >= 10) {
        const payloadLen = (rx[7]! << 16) | (rx[8]! << 8) | rx[9]!;
        const totalLen = 10 + payloadLen;
        if (rx.length < totalLen) break;
        const frameBytes = new Uint8Array(rx.subarray(0, totalLen));
        rx = rx.subarray(totalLen);
        const decoded = codec.decode(frameBytes);
        if (decoded.frame.flags === 0 && decoded.frame.payload.length > 0) {
          const parsed = JSON.parse(
            new TextDecoder().decode(decoded.frame.payload),
          );
          clearTimeout(timeout);
          socket.end();
          resolve(parsed as Record<string, unknown>);
          return;
        }
        if (decoded.frame.flags & /* VENT */ 0x08) {
          clearTimeout(timeout);
          socket.end();
          const parsed = JSON.parse(
            new TextDecoder().decode(decoded.frame.payload),
          );
          reject(new Error(`VENT: ${JSON.stringify(parsed)}`));
          return;
        }
      }
    });

    socket.on('error', (err) => {
      clearTimeout(timeout);
      reject(err);
    });
  });
}

function udpIngest(bytes: Uint8Array, codec: FlowCodec): Promise<Record<string, unknown>> {
  return new Promise((resolve, reject) => {
    const socket = createSocket('udp4');
    const timeout = setTimeout(() => {
      socket.close();
      reject(new Error('UDP timeout'));
    }, 5_000);

    socket.once('message', (msg) => {
      clearTimeout(timeout);
      socket.close();
      try {
        const decoded = codec.decode(new Uint8Array(msg));
        if (decoded.frame.flags & /* VENT */ 0x08) {
          reject(new Error(`VENT: ${new TextDecoder().decode(decoded.frame.payload)}`));
          return;
        }
        const parsed = JSON.parse(new TextDecoder().decode(decoded.frame.payload));
        resolve(parsed as Record<string, unknown>);
      } catch (err) {
        reject(err);
      }
    });

    socket.on('error', (err) => {
      clearTimeout(timeout);
      reject(err);
    });

    const req = codec.encode({
      streamId: 88,
      sequence: 0,
      flags: 0,
      payload: bytes,
    });
    socket.send(req, UDP_PORT, '127.0.0.1', (err) => {
      if (err) {
        clearTimeout(timeout);
        reject(err);
      }
    });
  });
}

describe('knotgraft-fabric / multi-transport smoke', () => {
  it('HTTP + TCP + UDP ingest same bytes → identical settled-block shape', async () => {
    const handle = await startKnotgraftFabric({
      httpPort: HTTP_PORT,
      flowTcpPort: TCP_PORT,
      flowUdpPort: UDP_PORT,
      defaultTenant: { hi: 0x1111_1111, lo: 0x2222_2222 },
      laneCount: 8,
      emitSql: false,
    });

    try {
      const codec = FlowCodec.createSync();
      const bigBytes = makeBytes(512);
      const smallBytes = makeBytes(256);

      const httpResult = await httpIngest(bigBytes);
      expect(httpResult['tenantHi']).toBe(0x1111_1111);
      expect(httpResult['tenantLo']).toBe(0x2222_2222);
      expect(httpResult['totalBytes']).toBe(512);

      const tcpResult = await tcpIngest(bigBytes, codec);
      expect(tcpResult['tenantHi']).toBe(0x1111_1111);
      expect(tcpResult['tenantLo']).toBe(0x2222_2222);
      expect(tcpResult['totalBytes']).toBe(512);
      expect(tcpResult['blocks']).toBe(httpResult['blocks']);
      expect(tcpResult['laneCount']).toBe(httpResult['laneCount']);

      const udpResult = await udpIngest(smallBytes, codec);
      expect(udpResult['tenantHi']).toBe(0x1111_1111);
      expect(udpResult['tenantLo']).toBe(0x2222_2222);
      expect(udpResult['totalBytes']).toBe(256);
    } finally {
      await handle.close();
    }
  });
});
